INSERT INTO `schools` (`id`, `nom`, `ville`, `type`, `description`, `presentation`, `dureeEtudes`, `diplome`, `admission`, `siteWeb`, `contact`, `telephone`, `adresse`, `logo`, `images`, `note`, `created_at`, `updated_at`) VALUES
(1, 'École Nationale d\'Informatique', 'Rabat', 'Université Publique', 'École d\'excellence en informatique et nouvelles technologies', 'L\'École Nationale d\'Informatique de Rabat forme des ingénieurs spécialisés dans les technologies de l\'information, l\'intelligence artificielle et la cybersécurité, avec une forte orientation pratique et recherche.', '5 ans', 'Diplôme d\'Ingénieur d\'État', 'Concours national après classes préparatoires ou licence scientifique', 'https://ensias.um5.ac.ma/', 'contact@eni.ma', NULL, NULL, '/images/ecole info logo.png', '[\"\\/images\\/ecole info rabat1.jpeg\",\"\\/images\\/ecole info rabart2.png\",\"\\/images\\/\\u00c9cole Nationale d\'Informatique.png\"]', 4.5, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(2, 'École Mohammadia d\'Ingénieurs', 'Rabat', 'École Publique d\'Ingénieurs', 'Prestigieuse école d\'ingénieurs marocaine', 'L\'EMI est l\'une des écoles d\'ingénieurs les plus prestigieuses du Maroc, connue pour la qualité de sa formation et l\'employabilité élevée de ses diplômés.', '5 ans', 'Diplôme d\'Ingénieur d\'État', 'Concours après classes préparatoires ou licence', 'https://www.emi.ac.ma', 'info@emi.ac.ma', NULL, NULL, '/images/ecole mohammadia logo.png', '[\"\\/images\\/mohammadia3.webp\",\"\\/images\\/mohammadia1.jpg\",\"\\/images\\/mohammadia2.jpg\"]', 4.7, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(3, 'Université Mohammed V de Rabat - Faculté des Sciences', 'Rabat', 'Université Publique', 'Formation scientifique fondamentale et appliquée', 'La Faculté des Sciences de Rabat offre une solide formation scientifique permettant d\'accéder à la recherche, à l\'enseignement ou aux métiers techniques.', '3 à 5 ans', 'Licence, Master, Doctorat', 'Baccalauréat scientifique', 'https://www.fs.um5.ac.ma', 'fs@um5.ac.ma', NULL, NULL, '/images/Université Mohammed V de Rabat - Faculté des Sciences logo.png', '[\"\\/images\\/Universit\\u00e9 Mohammed V de Rabat - Facult\\u00e9 des Sciences1.webp\",\"\\/images\\/Universit\\u00e9 Mohammed V de Rabat - Facult\\u00e9 des Sciences.png\",\"\\/images\\/Universit\\u00e9 Mohammed V de Rabat - Facult\\u00e9 des Sciences1.webp\"]', 4.0, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(4, 'Institut National des Postes et Télécommunications', 'Rabat', 'Établissement Public', 'Spécialisé dans les technologies de l\'information et de la communication', 'L\'INPT forme des ingénieurs et experts dans les télécommunications, les réseaux et le digital, avec une forte ouverture à l\'international.', '3 à 5 ans', 'Ingénieur, Master', 'Concours après bac ou classes préparatoires', 'https://www.inpt.ac.ma', 'contact@inpt.ac.ma', NULL, NULL, '/images/Institut National des Postes et Télécommunications logo.PNG', '[\"\\/images\\/institut national des postes et telecommunication.jpg\",\"\\/images\\/institut national des postes et telecommunication.jpg\",\"\\/images\\/institut national des postes et telecommunication.jpg\"]', 4.3, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(5, 'École Nationale Supérieure d\'Arts et Métiers', 'Meknès', 'École Publique d\'Ingénieurs', 'Formation d\'ingénieurs en génie mécanique et industriel', 'ENSAM Meknès est une référence dans la formation des ingénieurs en mécanique, industrie et systèmes énergétiques.', '5 ans', 'Diplôme d\'Ingénieur d\'État', 'Concours après classes préparatoires ou licence', 'https://www.ensam.ac.ma', 'contact@ensam.ac.ma', NULL, NULL, '/images/ENSAM Meknès logo.png', '[\"\\/images\\/\\u00c9cole Nationale Sup\\u00e9rieure d\'Arts et M\\u00e9tiers.webp\",\"\\/images\\/\\u00c9cole Nationale Sup\\u00e9rieure d\'Arts et M\\u00e9tiers.webp\",\"\\/images\\/\\u00c9cole Nationale Sup\\u00e9rieure d\'Arts et M\\u00e9tiers.webp\"]', 4.4, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(6, 'Faculté de Médecine et de Pharmacie de Rabat', 'Rabat', 'Université Publique de Santé', 'Formation médicale et pharmaceutique de référence', 'La Faculté de Médecine et de Pharmacie de Rabat est l\'un des plus anciens établissements de santé au Maroc, formant des médecins, pharmaciens et chirurgiens-dentistes hautement qualifiés.', '5 à 7 ans', 'Doctorat en Médecine, Pharmacie ou Médecine Dentaire', 'Concours national après baccalauréat scientifique', 'https://www.fmpr.ac.ma', 'contact@fmpr.ac.ma', NULL, NULL, '/images/medecine rabat logo.png', '[\"\\/images\\/medecine rabat1.webp\",\"\\/images\\/medecine rabat2.webp\",\"\\/images\\/Facult\\u00e9 M\\u00e9decine Rabat.webp\"]', 4.6, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(7, 'École Nationale de Commerce et de Gestion de Casablanca', 'Casablanca', 'École Publique de Commerce', 'Formation en management et sciences commerciales', 'L\'ENCG Casablanca, composante de l\'Université Hassan II de Casablanca et créée en 2007, forme des cadres de haut niveau dans les domaines du commerce et de la gestion. L\'école propose un enseignement interactif associant expérience et théorie pour former des managers capables d\'appréhender les grands enjeux socio-économiques dans un cadre multinational.', '5 ans (dont 3 ans de tronc commun)', 'Diplôme des Écoles Nationales de Commerce et de Gestion (Bac+5)', 'Concours national après baccalauréat via la plateforme tafem.ma', 'https://www.encgcasa.ac.ma', 'encgcasa@encgcasa.ac.ma', '05 22 66 08 52', 'Beau site, B.P 2725 Ain Sebaâ, Casablanca', '/images/encg casa.png', '[\"\\/images\\/encg casa.png\",\"\\/images\\/encg casa.png\",\"\\/images\\/encg casa.png\"]', 4.2, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(8, 'Université Hassan II - Faculté des Sciences et Techniques', 'Casablanca', 'Université Publique', 'Formation technique et scientifique de haut niveau', 'La FST Hassan II forme des techniciens et ingénieurs spécialisés dans les sciences appliquées et les technologies industrielles.', '3 à 5 ans', 'Licence, Master, Ingénieur', 'Baccalauréat scientifique', 'https://www.fst.ac.ma', 'fst@uh2.ac.ma', NULL, NULL, '/images/Université Hassan II - Faculté des Sciences et Techniques logo.png', '[\"\\/images\\/Universit\\u00e9 Hassan II - Facult\\u00e9 des Sciences et Techniques.jpg\",\"\\/images\\/Universit\\u00e9 Hassan II - Facult\\u00e9 des Sciences et Techniques.jpg\",\"\\/images\\/Universit\\u00e9 Hassan II - Facult\\u00e9 des Sciences et Techniques.jpg\"]', 4.1, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(9, 'École Nationale d\'Architecture', 'Rabat', 'École Publique d\'Architecture', 'Formation d\'architectes et d\'urbanistes', 'L\'ENA Rabat forme les futurs architectes du Maroc avec une forte approche créative, technique et urbaine.', '6 ans', 'Diplôme d\'Architecte', 'Concours après baccalauréat', 'https://www.ena.ma', 'contact@ena.ma', NULL, NULL, '/images/ecole rchitecture rabat logo.png', '[\"\\/images\\/\\u00c9cole Nationale d\'Architecture.webp\",\"\\/images\\/ecole rchitecture rabat logo.png\",\"\\/images\\/\\u00c9cole Nationale d\'Architecture.webp\"]', 4.5, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(10, 'Institut Agronomique et Vétérinaire Hassan II', 'Rabat', 'Établissement Public Agronomique', 'Excellence dans les domaines agronomiques et vétérinaires', 'L\'IAV Hassan II est une référence nationale pour la formation des ingénieurs agronomes et des vétérinaires.', '5 à 6 ans', 'Ingénieur, Docteur vétérinaire', 'Concours après classes préparatoires ou bac scientifique', 'https://www.iav.ac.ma', 'contact@iav.ac.ma', NULL, NULL, '/images/Institut Agronomique et Vétérinaire Hassan II logo.png', '[\"\\/images\\/Institut Agronomique et V\\u00e9t\\u00e9rinaire Hassan II.webp\",\"\\/images\\/Institut Agronomique et V\\u00e9t\\u00e9rinaire Hassan II logo.png\",\"\\/images\\/Institut Agronomique et V\\u00e9t\\u00e9rinaire Hassan II.webp\"]', 4.4, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(11, 'Université Ibn Tofail - Faculté des Sciences', 'Kénitra', 'Université Publique', 'Enseignement scientifique pluridisciplinaire', 'La Faculté des Sciences de Kénitra offre une formation solide en sciences fondamentales et appliquées.', '3 à 5 ans', 'Licence, Master', 'Baccalauréat scientifique', 'https://www.uit.ac.ma', 'contact@uit.ac.ma', NULL, NULL, '/images/Université Ibn Tofail - Faculté des Sciences logo.png', '[\"\\/images\\/Universit\\u00e9 Ibn Tofail - Facult\\u00e9 des Sciences.webp\",\"\\/images\\/Universit\\u00e9 Ibn Tofail - Facult\\u00e9 des Sciences.webp\",\"\\/images\\/Universit\\u00e9 Ibn Tofail - Facult\\u00e9 des Sciences.webp\"]', 3.9, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(12, 'École Normale Supérieure de l\'Enseignement Technique', 'Rabat', 'École Publique de Formation', 'Formation des enseignants pour l\'enseignement technique', 'L\'ENSET forme des professeurs et formateurs spécialisés dans l\'enseignement technique et professionnel.', '3 à 5 ans', 'Licence, Master en Enseignement', 'Concours après bac ou licence', 'https://www.enset.ma', 'contact@enset.ma', NULL, NULL, '/images/École Normale Supérieure de l\'Enseignement Technique logo.png', '[\"\\/images\\/\\u00c9cole Normale Sup\\u00e9rieure de l\'Enseignement Technique.png\",\"\\/images\\/\\u00c9cole Normale Sup\\u00e9rieure de l\'Enseignement Technique.png\",\"\\/images\\/\\u00c9cole Normale Sup\\u00e9rieure de l\'Enseignement Technique.png\"]', 4.0, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(13, 'Université Cadi Ayyad - Faculté des Sciences Semlalia', 'Marrakech', 'Université Publique', 'Centre de recherche scientifique renommé', 'La Faculté des Sciences Semlalia est un centre de recherche reconnu à l\'échelle nationale et internationale.', '3 à 8 ans', 'Licence, Master, Doctorat', 'Baccalauréat scientifique', 'https://www.uca.ma', 'contact@uca.ma', NULL, NULL, '/images/Université Cadi Ayyad - Faculté des Sciences Semlalia logo.png', '[\"\\/images\\/Universit\\u00e9 Cadi Ayyad - Facult\\u00e9 des Sciences Semlalia.jpg\",\"\\/images\\/Universit\\u00e9 Cadi Ayyad - Facult\\u00e9 des Sciences Semlalia.jpg\",\"\\/images\\/Universit\\u00e9 Cadi Ayyad - Facult\\u00e9 des Sciences Semlalia.jpg\"]', 4.3, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(14, 'École Nationale Forestière d\'Ingénieurs', 'Salé', 'École Publique d\'Ingénieurs', 'Spécialisée dans les sciences forestières et environnementales', 'Cette école forme des ingénieurs spécialisés dans la protection des forêts, de l\'environnement et du développement durable.', '5 ans', 'Ingénieur d\'État', 'Concours après classes préparatoires', 'https://www.enfi.ac.ma', 'contact@enfi.ac.ma', NULL, NULL, '/images/École Nationale Forestièr logoe d\'Ingénieurs.png', '[\"\\/images\\/\\u00c9cole Nationale Foresti\\u00e8re d\'Ing\\u00e9nieurs.png\",\"\\/images\\/\\u00c9cole Nationale Foresti\\u00e8re d\'Ing\\u00e9nieurs.png\",\"\\/images\\/\\u00c9cole Nationale Foresti\\u00e8re d\'Ing\\u00e9nieurs.png\"]', 4.2, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(15, 'Faculté des Sciences Juridiques, Économiques et Sociales', 'Rabat', 'Université Publique', 'Formation en sciences humaines et sociales', 'Cette faculté prépare les étudiants aux métiers du droit, de l\'économie et de la gestion publique et privée.', '3 à 5 ans', 'Licence, Master', 'Baccalauréat', 'https://www.fsjesr.ma', 'contact@fsjesr.ma', NULL, NULL, '/images/Faculté des Sciences Juridiques, Économiques et Sociales logo.png', '[\"\\/images\\/Facult\\u00e9 des Sciences Juridiques, \\u00c9conomiques et Sociales.jpg\",\"\\/images\\/Facult\\u00e9 des Sciences Juridiques, \\u00c9conomiques et Sociales.jpg\",\"\\/images\\/Facult\\u00e9 des Sciences Juridiques, \\u00c9conomiques et Sociales.jpg\"]', 4.1, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(16, 'Institut Supérieur de l\'Information et de la Communication', 'Rabat', 'Établissement Public', 'Formation aux métiers de l\'information et de la communication', 'L\'ISIC forme des journalistes et communicants capables de travailler dans les médias modernes.', '3 ans', 'Licence professionnelle', 'Concours après baccalauréat', 'https://www.isic.ma', 'contact@isic.ma', NULL, NULL, '/images/Institut Supérieur de l\'Information et de la Communication logo.png', '[\"\\/images\\/Institut Sup\\u00e9rieur de l\'Information et de la Communication.webp\",\"\\/images\\/Institut Sup\\u00e9rieur de l\'Information et de la Communication1.webp\",\"\\/images\\/Institut Sup\\u00e9rieur de l\'Information et de la Communication.webp\"]', 4.3, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(17, 'Université Abdelmalek Essaâdi - Faculté des Sciences', 'Tétouan', 'Université Publique', 'Pôle scientifique dans le nord du Maroc', 'Cette faculté joue un rôle clé dans le développement scientifique et technologique du nord du Maroc.', '3 à 5 ans', 'Licence, Master', 'Baccalauréat scientifique', 'https://www.uae.ma', 'contact@uae.ma', NULL, NULL, '/images/Université Abdelmalek Essaâdi - Faculté des Sciences logo.png', '[\"\\/images\\/Universit\\u00e9 Abdelmalek Essa\\u00e2di - Facult\\u00e9 des Sciences.webp\",\"\\/images\\/Universit\\u00e9 Abdelmalek Essa\\u00e2di - Facult\\u00e9 des Sciences.webp\",\"\\/images\\/Universit\\u00e9 Abdelmalek Essa\\u00e2di - Facult\\u00e9 des Sciences.webp\"]', 3.8, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(18, 'École Nationale Supérieure d\'Électricité et Mécanique', 'Casablanca', 'École Publique d\'Ingénieurs', 'Formation d\'ingénieurs en génie électrique et mécanique', 'ENSEM est une école d\'ingénieurs réputée pour la qualité de sa formation en électricité, mécanique et automatisme.', '5 ans', 'Ingénieur d\'État', 'Concours après classes préparatoires', 'https://www.ensem.ac.ma', 'contact@ensem.ac.ma', NULL, NULL, '/images/École Nationale Supérieure d\'Électricité et Mécanique logo.jpg', '[\"\\/images\\/\\u00c9cole Nationale Sup\\u00e9rieure d\'\\u00c9lectricit\\u00e9 et M\\u00e9canique.png\",\"\\/images\\/\\u00c9cole Nationale Sup\\u00e9rieure d\'\\u00c9lectricit\\u00e9 et M\\u00e9canique.png\",\"\\/images\\/\\u00c9cole Nationale Sup\\u00e9rieure d\'\\u00c9lectricit\\u00e9 et M\\u00e9canique.png\"]', 4.4, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(19, 'Faculté des Lettres et des Sciences Humaines', 'Fès', 'Université Publique', 'Enseignement des humanités et sciences sociales', 'Cette faculté forme des spécialistes des langues, de la culture et des sciences humaines.', '3 à 5 ans', 'Licence, Master', 'Baccalauréat', 'https://www.flshfes.ac.ma', 'contact@flshfes.ac.ma', NULL, NULL, '/images/Faculté des Lettres et des Sciences Humaines logo.jpg', '[\"\\/images\\/Facult\\u00e9 des Lettres et des Sciences Humaines.jpeg\",\"\\/images\\/Facult\\u00e9 des Lettres et des Sciences Humaines.jpeg\",\"\\/images\\/Facult\\u00e9 des Lettres et des Sciences Humaines.jpeg\"]', 3.9, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(20, 'ISTA Bab Tizimi - OFPPT', 'Meknès', 'Institut Spécialisé de Technologie Appliquée', 'Institut de formation professionnelle technique', 'L\'ISTA Bab Tizimi est un établissement de l\'OFPPT spécialisé dans les formations techniques et technologiques à Meknès.', '2 ans', 'Technicien Spécialisé (TS)', 'Baccalauréat (toutes filières selon spécialité)', 'https://www.ofppt.ma', 'istameknes@ofppt.ma', '+212 5355-30878', 'Quartier Bab Tizimi, Route de Fès, Meknès', '/images/ofppt.png', '[\"\\/images\\/BAB TIZIMI.webp\",\"\\/images\\/BAB TIZIMI.webp\",\"\\/images\\/BAB TIZIMI.webp\"]', 4.0, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(21, 'École Hassania des Travaux Publics', 'Casablanca', 'École Publique d\'Ingénieurs', 'École d\'ingénieurs spécialisée en génie civil et travaux publics', 'L\'EHTP forme des ingénieurs de haut niveau dans les domaines du génie civil, des travaux publics et de l\'urbanisme.', '5 ans', 'Diplôme d\'Ingénieur d\'État', 'Concours national', 'https://www.ehtp.ac.ma', 'info@ehtp.ac.ma', NULL, NULL, '/images/ecole hassania des travaux public.png', '[\"\\/images\\/ecole hassania des travaux public.png\",\"\\/images\\/ecole hassania des travaux public.png\",\"\\/images\\/ecole hassania des travaux public.png\"]', 4.6, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(22, 'École Supérieure de Technologie de Meknès', 'Meknès', 'École Publique de Technologie', 'Formation technologique spécialisée', 'L\'EST Meknès se spécialise dans les technologies agro-alimentaires et biotechnologiques adaptées à la région.', '2 ans', 'Diplôme de Technicien Supérieur', 'Baccalauréat scientifique ou technique', 'https://www.estmeknes.ac.ma', 'estmeknes@estmeknes.ac.ma', NULL, NULL, '/images/est meknes logo.png', '[\"\\/images\\/est meknes.png\",\"\\/images\\/est meknes.png\",\"\\/images\\/est meknes.png\"]', 4.0, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(23, 'École Nationale des Sciences Appliquées de Marrakech', 'Marrakech', 'École Publique d\'Ingénieurs', 'Professional public engineering school created to diversify university offerings and train versatile state engineers to meet regional and national socio-economic needs.', 'ENSA Marrakech (ENSAM), established in 2000, is a public professional higher education institution and a component of Cadi Ayyad University. Its creation aimed to diversify the university\'s programs and stimulate the socio-economic and industrial environment of the Marrakech region. The school\'s mission is to train versatile, highly qualified state engineers in open specializations with strong development potential.', '5 ans (2 ans de cycle préparatoire + 3 ans de cycle ingénieur)', 'Diplôme d\'Ingénieur d\'État (Bac+5)', 'Concours national via la plateforme www.ensa-concours.ma', 'www.ensa.ac.ma', 'sefyani@ensa.ac.ma', '0524434745', 'E.N.S.A - BP 575 Avenue Abdelkarim Khattabi, Guéliz Marrakech Maroc', '/images/ensa marrakech.png', '[\"\\/images\\/ensa marrakech.png\",\"\\/images\\/ensa marrakech.png\",\"\\/images\\/ensa marrakech.png\"]', 4.3, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(24, 'Université Sidi Mohamed Ben Abdellah - Faculté des Sciences', 'Fès', 'Université Publique', 'Formation scientifique fondamentale', 'La Faculté des Sciences de Fès propose des formations scientifiques complètes de la licence au doctorat.', '3 à 5 ans', 'Licence, Master, Doctorat', 'Baccalauréat scientifique', 'https://www.fs.usmba.ac.ma', 'fs@usmba.ac.ma', NULL, NULL, '/images/fst fes.png', '[\"\\/images\\/fst fes.png\",\"\\/images\\/fst fes.png\",\"\\/images\\/fst fes.png\"]', 3.9, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(25, 'École Nationale des Sciences Appliquées de Fès', 'Fès', 'École Publique d\'Ingénieurs', 'École d\'ingénieurs en sciences appliquées', 'L\'ENSA Fès forme des ingénieurs dans les domaines de l\'informatique, génie civil et génie des procédés.', '5 ans', 'Diplôme d\'Ingénieur d\'État', 'Concours national', 'https://www.ensaf.ac.ma', 'contact@ensaf.ac.ma', NULL, NULL, '/images/ensa fes logo.png', '[\"\\/images\\/ensa fes.png\",\"\\/images\\/ensa fes.png\",\"\\/images\\/ensa fes.png\"]', 4.2, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(26, 'Université Abdelmalek Essaâdi - Faculté des Sciences de Tanger', 'Tanger', 'Université Publique', 'Formation scientifique et technique', 'La Faculté des Sciences de Tanger offre des formations scientifiques avec une orientation vers les sciences de la terre et l\'environnement.', '3 à 5 ans', 'Licence, Master, Doctorat', 'Baccalauréat scientifique', 'https://www.fst.ac.ma', 'fst@uae.ac.ma', NULL, NULL, '/images/fst tanger.png', '[\"\\/images\\/fst tanger.png\",\"\\/images\\/fst tanger.png\",\"\\/images\\/fst tanger.png\"]', 3.8, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(27, 'École Nationale de Commerce et de Gestion de Tanger', 'Tanger', 'École Publique de Commerce', 'Établissement supérieur public de haute formation à la gestion des entreprises et des organisations.', 'L\'ENCG Tanger, ouverte en 1995 et rattachée à l\'Université Abdelmalek Essaadi, est l\'une des premières ENCG du Maroc. Elle s\'est construite sur un héritage prestigieux en sciences de gestion. Son activité structurée autour de trois axes (formation initiale, formation continue, recherche appliquée-conseil) vise à former des gestionnaires modernes, aptes à relever le défi de la compétitivité de l\'entreprise marocaine.', '5 ans (10 semestres, dont un tronc commun de 3 ans/6 semestres)', 'Diplôme des Écoles Nationales de Commerce et de Gestion (Bac+5)', 'Concours national via la plateforme tafem.ma pour les bacheliers, avec présélection sur la moyenne du baccalauréat, suivi du test TAFEM.', 'www.encgt.ma', 'encgtanger@encgt.ma', '0539313487/88/89', 'ENCG de Tanger Route de l\'aéroport B.P 1255 - 90000 Tanger Principal', '/images/encg tanger.png', '[\"\\/images\\/encg tanger.png\",\"\\/images\\/encg tanger.png\",\"\\/images\\/encg tanger.png\"]', 4.3, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(28, 'Université Ibn Zohr - Faculté des Sciences', 'Agadir', 'Université Publique', 'Formation scientifique et recherche', 'La Faculté des Sciences d\'Agadir se spécialise dans les sciences de la vie, la géologie et l\'environnement avec une orientation régionale.', '3 à 5 ans', 'Licence, Master, Doctorat', 'Baccalauréat scientifique', 'https://www.fsa.ac.ma', 'fsa@uiz.ac.ma', NULL, NULL, '/images/université ibn zohr faculté des sciences agadir logo.png', '[\"\\/images\\/Universit\\u00e9 Ibn Zohr  Facult\\u00e9 des Sciences.jpg\",\"\\/images\\/Universit\\u00e9 Ibn Zohr - Facult\\u00e9 des Sciences1.webp\",\"\\/images\\/Universit\\u00e9 Ibn Zohr  Facult\\u00e9 des Sciences.jpg\"]', 3.9, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(29, 'École Nationale des Sciences Appliquées d\'Agadir', 'Agadir', 'École Publique d\'Ingénieurs', 'Public engineering school aiming to train engineers in diverse technological disciplines through a 5-year program.', 'ENSA Agadir, founded in September 1999 and affiliated with Ibn Zohr University, is a polytechnic school open to multiple technologies. Its goal is to train engineers through a curriculum that includes a 2-year preparatory cycle followed by 3 years of specialization. The school\'s success is attributed to its policy of aligning with industry needs and continuously updating its programs to integrate new technologies. It is also active in scientific research and hosts a doctoral program.', '5 ans (2 ans de cycle préparatoire + 3 ans de cycle ingénieur)', 'Diplôme d\'Ingénieur d\'État (Bac+5)', 'Concours national via la plateforme www.ensa-concours.ma', 'www.ensa-agadir.ac.ma', 'contact@ensa-agadir.ac.ma', '0528228313', 'E.N.S.A - B.P: 1136 Agadir - Maroc', '/images/ensa agadir logo.jpg', '[\"\\/images\\/ensa agadir.jpg\",\"\\/images\\/ensa agadir.webp\",\"\\/images\\/ensa agadir.jpg\"]', 4.0, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(30, 'Université Mohammed Premier - Faculté des Sciences', 'Oujda', 'Université Publique', 'Formation scientifique et recherche', 'La Faculté des Sciences d\'Oujda offre des formations scientifiques avec une orientation vers les besoins de la région orientale.', '3 à 5 ans', 'Licence, Master, Doctorat', 'Baccalauréat scientifique', 'https://www.fso.ump.ac.ma', 'fso@ump.ac.ma', NULL, NULL, '/images/Universite Mohammed Premier Oujda.png', '[\"\\/images\\/Universite Mohammed Premier Oujda.png\",\"\\/images\\/Universite Mohammed Premier Oujda.png\",\"\\/images\\/Universite Mohammed Premier Oujda.png\"]', 3.7, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(31, 'École Nationale des Sciences Appliquées d\'Oujda', 'Oujda', 'École Publique d\'Ingénieurs', 'First and only major state engineering school in the Oriental region, with a comprehensive mission covering initial and continuous training, research, and strong industrial partnership.', 'ENSA Oujda (ENSAO), created in 2001, is the first and only major state engineering school in the Oriental region. Located on the university campus, it aims to diversify training within Mohammed Premier University and energize the regional and national socio-economic and industrial environment. It has a broad mission encompassing the training of highly qualified state engineers, scientific and technological research, R&D, and continuous training, with a strong focus on industrial synergy.', '5 ans (2 ans de cycle préparatoire + 3 ans de cycle ingénieur)', 'Diplôme d\'Ingénieur d\'État (Bac+5)', 'Concours national via la plateforme www.ensa-concours.ma', 'wwwensa.univ-oujda.ac.ma', 'omar@ensa.ump.ma', '0536 50 54 70 / 0536 50 54 71', 'ENSA, BP 669, OUJDA 60000 MAROC', '/images/École Nationale des Sciences Appliquées d\'Oujda logo.png', '[\"\\/images\\/ENSA Oujda.png\",\"\\/images\\/ENSA Oujda.png\",\"\\/images\\/ENSA Oujda.png\"]', 4.1, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(32, 'Université Chouaib Doukkali - Faculté des Sciences', 'El Jadida', 'Université Publique', 'Formation scientifique et technique', 'La Faculté des Sciences d\'El Jadida propose des formations scientifiques avec une orientation côtière et marine.', '3 à 5 ans', 'Licence, Master, Doctorat', 'Baccalauréat scientifique', 'https://www.fs.ucd.ac.ma', 'fs@ucd.ac.ma', NULL, NULL, '/images/Université Chouaib Doukkali - Faculté des Sciences logo.png', '[\"\\/images\\/Universit\\u00e9 Chouaib Doukkali  Facult\\u00e9 des Sciences el jadida.jpg\",\"\\/images\\/Universit\\u00e9 Chouaib Doukkali  Facult\\u00e9 des Sciences el jadida.jpg\",\"\\/images\\/Universit\\u00e9 Chouaib Doukkali  Facult\\u00e9 des Sciences el jadida.jpg\"]', 3.8, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(33, 'École Supérieure de Technologie de Casablanca', 'Casablanca', 'École Publique de Technologie', 'Formation technologique supérieure', 'L\'EST de Casablanca forme des techniciens supérieurs spécialisés dans les technologies industrielles et la maintenance.', '2 ans', 'Diplôme de Technicien Supérieur', 'Baccalauréat scientifique ou technique', 'https://www.est.ac.ma', 'estcasa@est.ac.ma', NULL, NULL, '/images/est casablanca.png', '[\"\\/images\\/est casablanca.png\",\"\\/images\\/est casablanca.png\",\"\\/images\\/est casablanca.png\"]', 4.0, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(34, 'École Supérieure de Technologie de Salé', 'Salé', 'École Publique de Technologie', 'Formation technologique appliquée', 'L\'EST Salé forme des techniciens supérieurs en informatique, électronique, mécanique et gestion.', '2 ans', 'Diplôme de Technicien Supérieur', 'Baccalauréat scientifique ou technique', 'https://www.estsale.ac.ma', 'estsale@estsale.ac.ma', NULL, NULL, '/images/ESTS sale.webp', '[\"\\/images\\/ESTS sale.webp\",\"\\/images\\/ESTS sale.webp\",\"\\/images\\/ESTS sale.webp\"]', 4.1, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(35, 'École Nationale de Commerce et de Gestion de Kénitra', 'Kénitra', 'École Publique de Commerce', 'Formation en techniques commerciales et sciences de gestion des entreprises', 'L\'ENCG Kénitra, faisant partie du réseau national des ENCG et affiliée à l\'Université Ibn Tofail, a été créée en 2005. Elle est un établissement public d\'enseignement supérieur spécialisé dans la formation, la recherche et la formation continue dans le domaine du commerce et de la gestion. L\'école propose un enseignement modulaire de haut niveau, alternant théorie et pratique, et accorde une large place à la participation des étudiants à la vie associative et à leur ouverture sur l\'environnement socio-économique.', '5 ans (10 semestres, dont un tronc commun de 3 ans/6 semestres)', 'Diplôme des Écoles Nationales de Commerce et de Gestion (Bac+5)', 'Concours national via la plateforme tafem.ma pour les titulaires d\'un baccalauréat pertinent (sciences économiques, maths, sciences expérimentales, etc.) suivi d\'un test (TAFEM) et d\'un entretien.', 'www.univ-ibntofail.ac.ma', 'Information non spécifiée sur la page', '05 37 32 94 21/22', 'ENCG B.P 1420, Kénitra 14000- Maroc', '/images/École Nationale de Commerce et de Gestion de Kénitra logo.png', '[\"\\/images\\/encg kenitra.jpg\",\"\\/images\\/encg kenitra.jpg\",\"\\/images\\/encg kenitra.jpg\"]', 4.0, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(36, 'École Nationale de Commerce et de Gestion de Settat', 'Settat', 'École Publique de Commerce', 'Formation en sciences de gestion et techniques commerciales', 'L\'ENCG Settat, constituante de l\'Université Hassan 1er, est une école de commerce publique créée en 2007. Elle a pour vocation de former des cadres supérieurs et des décideurs dans les domaines du management et du commerce, capables de s\'adapter aux évolutions du monde économique. L\'école promeut une pédagogie active basée sur des études de cas, des simulations et une forte interaction avec le monde professionnel.', '5 ans (10 semestres, dont un tronc commun de 3 ans/6 semestres)', 'Diplôme des Écoles Nationales de Commerce et de Gestion (Bac+5)', 'Concours national après le baccalauréat via la plateforme tafem.ma. Les titulaires d\'un bac scientifique, économique ou technique sont les principaux concernés.', 'https://encgset.ac.ma/', 'contact@encgset.ac.ma', '05 23 72 04 50', 'B.P 539, Route de Casablanca, Settat, Maroc', '/images/encg settat.jpg', '[\"\\/images\\/encg settat.jpg\",\"\\/images\\/encg settat.jpg\",\"\\/images\\/encg settat.jpg\"]', 4.1, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(37, 'École Nationale de Commerce et de Gestion de Marrakech', 'Marrakech', 'École Publique de Commerce', 'École de commerce et de gestion créée pour répondre aux besoins des entreprises en cadres et managers.', 'L\'ENCG Marrakech, créée en 2004 et affiliée à l\'Université Cadi Ayyad, a pour vocation de former des managers performants, dotés d\'aptitudes relationnelles et d\'un savoir-faire adapté au développement de l\'environnement économique national et international. Elle vise à répondre directement aux attentes des entreprises privées et publiques en matière de cadres dans les domaines du commerce et de la gestion.', '5 ans (10 semestres, dont un tronc commun de 3 ans/6 semestres)', 'Diplôme des Écoles Nationales de Commerce et de Gestion (Bac+5)', 'Concours national après le baccalauréat via la plateforme tafem.ma', 'www.encg.ucam.ac.ma', 'encg@encg.ucam.ac.ma', '05 24 30 46 92', 'ENCG de Marrakech av. Allal El Fassi BP 3748', '/images/encg marrakech.png', '[\"\\/images\\/encg marrakech.png\",\"\\/images\\/encg marrakech.png\",\"\\/images\\/encg marrakech.png\"]', 4.0, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(38, 'École Nationale de Commerce et de Gestion d\'El Jadida', 'El Jadida', 'École Publique de Commerce', 'Formation professionnalisante en commerce et gestion basée sur les normes des grandes écoles.', 'L\'ENCG El Jadida, affiliée à l\'Université Chouaïb Doukkali, offre une formation professionnalisante conçue sur le modèle des grandes écoles de commerce. Son cursus vise à préparer les futurs lauréats à relever les défis de la mondialisation, du développement technologique et de l\'évolution des marchés. L\'école met l\'accent sur l\'acquisition de compétences fondamentales et une spécialisation progressive, le tout étalé sur un programme de 10 semestres.', '5 ans (10 semestres, dont un tronc commun de 3 ans/6 semestres)', 'Diplôme des Écoles Nationales de Commerce et de Gestion (Bac+5)', 'Concours national après le baccalauréat via la plateforme tafem.ma', 'www.encgj.ac.ma', 'Information non spécifiée sur la page', '05 23 39 44 35', 'ENCG - El Jadida Angle Avenue Ahmed Chaouki et Rue de Fés - B.P.122 – 24000 El Jadida', '/images/encg eljadida.png', '[\"\\/images\\/encg eljadida.png\",\"\\/images\\/encg eljadida.png\",\"\\/images\\/encg eljadida.png\"]', 3.9, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(39, 'École Nationale de Commerce et de Gestion d\'Agadir', 'Agadir', 'École Publique de Commerce', 'Établissement public modélisé sur les grandes écoles européennes, connu pour son excellence et son fort taux d\'insertion professionnelle.', 'L\'ENCG Agadir, créée en 1994 et affiliée à l\'Université Ibn Zohr, est l\'une des plus anciennes et prestigieuses ENCG du Maroc. Modélisée sur les grandes écoles de commerce européennes, elle s\'est distinguée en remportant des prix nationaux et internationaux en gestion. L\'école est réputée pour son taux d\'insertion professionnelle exceptionnel, dépassant les 95%. Elle propose un arsenal pédagogique riche et une grande diversité de choix de spécialités, tout en ayant été pionnière dans l\'adoption du système LMD.', '5 ans (10 semestres organisés selon le système LMD, avec un tronc commun de 3 ans)', 'Diplôme des Écoles Nationales de Commerce et de Gestion (Bac+5)', 'Concours national après le baccalauréat via la plateforme tafem.ma', 'www.encg-agadir.ac.ma', 'info@encg-agadir.ac.ma', '0528225739/48', 'ENCG BP 37/S 80000, Agadir', '/images/encg agadir.png', '[\"\\/images\\/encg agadir.png\",\"\\/images\\/encg agadir.png\",\"\\/images\\/encg agadir.png\"]', 4.4, '2026-04-11 15:06:16', '2026-04-11 15:06:16'),
(40, 'École Nationale de Commerce et de Gestion de Fès', 'Fès', 'École Publique de Commerce', 'Établissement leader dans la formation en gestion d\'entreprises et d\'organisations.', 'Implantée à Fès en 2007 et composante de l\'Université Sidi Mohamed Ben Abdellah, l\'ENCG Fès est reconnue comme un établissement leader au Maroc. Fondée sur la devise « Instruire pour construire », elle s\'appuie sur un corps professoral dévoué pour former des cadres capables de répondre aux besoins évolutifs et compétitifs du marché national et international. L\'école a pour vocation la formation initiale, la formation continue et la recherche dans le commerce et la gestion.', '5 ans (dont 3 ans de tronc commun)', 'Diplôme des Écoles Nationales de Commerce et de Gestion (Bac+5)', 'Concours national après baccalauréat via la plateforme tafem.ma. Des passerelles existent pour les titulaires de Bac+2 (au 5ème semestre) et Bac+3 (au 7ème semestre).', 'www.encg-usmba.ma', 'Information non spécifiée sur la page', '0535605057', 'ENCG Route d\'Imouzzer B.P.2626 Fès 30000 Maroc', '/images/encg fes.png', '[\"\\/images\\/encg fes.png\",\"\\/images\\/encg fes.png\",\"\\/images\\/encg fes.png\"]', 4.0, '2026-04-11 15:06:17', '2026-04-11 15:06:17'),
(41, 'École Nationale de Commerce et de Gestion d\'Oujda', 'Oujda', 'École Publique de Commerce', 'Établissement public de haute formation à la gestion des entreprises, répondant aux besoins en cadres de haut niveau.', 'L\'ENCG Oujda, rattachée à l\'Université Mohammed Premier, a été créée par décret en 2006 mais a démarré ses activités d\'enseignement dès 2004. Elle fait partie du réseau des ENCG et vise à répondre aux besoins croissants des entreprises en cadres de haut niveau. L\'école a d\'abord délivré un diplôme Bac+4 avant de se conformer au standard Bac+5 du réseau.', '5 ans (dont 3 ans de tronc commun)', 'Diplôme des Écoles Nationales de Commerce et de Gestion (Bac+5)', 'Concours national après baccalauréat via la plateforme tafem.ma', 'www.encgo.ump.ma', 'service.informatique.encgo@gmail.com', '536506983/85/89', 'ENCG Complexe universitaire BP 658 - Oujda principale 60000', '/images/École Nationale de Commerce et de Gestion d\'Oujda logo.jpg', '[\"\\/images\\/encg oujda.webp\",\"\\/images\\/encg oujda.webp\",\"\\/images\\/encg oujda.webp\"]', 3.8, '2026-04-11 15:06:17', '2026-04-11 15:06:17');
